const p = msg.payload;
if (!p || !p.device_id || !p.patient_id || !p.timestamp || !Array.isArray(p.samples) || p.samples.length === 0) {
    node.warn('Invalid accelerometer payload');
    return [null, null];
}
const s = p.samples[0];
for (const axis of ['x','y','z']) {
    if (typeof s[axis] !== 'number' || !Number.isFinite(s[axis])) return [null, null];
}
const normalized = {
    schema_version: 1, device_id: String(p.device_id), patient_id: String(p.patient_id),
    timestamp: Number(p.timestamp), sequence: Number(p.sequence || 0), type: 'accgyro',
    x: s.x, y: s.y, z: s.z, quality: String(p.quality || 'unknown'),
    source_topic: msg.topic, simulation_state: p.simulation_state || null
};
const mqttMsg = { topic: 'smartback/normalized/posture', payload: normalized, qos: 1 };
const tags = `device_id=${normalized.device_id},patient_id=${normalized.patient_id},quality=${normalized.quality}`;
const fields = `x=${normalized.x},y=${normalized.y},z=${normalized.z},sequence=${normalized.sequence}i`;
const influxMsg = {
    method: 'POST',
    url: `${env.get('INFLUXDB_URL')}/api/v2/write?org=${env.get('INFLUXDB_ORG')}&bucket=${env.get('INFLUXDB_BUCKET')}&precision=ms`,
    headers: {'Authorization': `Token ${env.get('INFLUXDB_TOKEN')}`, 'Content-Type': 'text/plain; charset=utf-8'},
    payload: `raw_accelerometer,${tags} ${fields} ${normalized.timestamp}`
};
return [mqttMsg, influxMsg];

const p = msg.payload;
if (!p || !p.device_id || !p.patient_id || !p.timestamp || typeof p.state_of_charge !== 'number') return [null, null];
const normalized = {schema_version: 1, device_id: String(p.device_id), patient_id: String(p.patient_id), timestamp: Number(p.timestamp), type: 'battery', state_of_charge: p.state_of_charge, charging: Boolean(p.charging), quality: String(p.quality || 'unknown')};
const mqttMsg = {topic: 'smartback/normalized/device', payload: normalized, qos: 1, retain: true};
const tags = `device_id=${normalized.device_id},patient_id=${normalized.patient_id}`;
const influxMsg = {method: 'POST', url: `${env.get('INFLUXDB_URL')}/api/v2/write?org=${env.get('INFLUXDB_ORG')}&bucket=${env.get('INFLUXDB_BUCKET')}&precision=ms`, headers: {'Authorization': `Token ${env.get('INFLUXDB_TOKEN')}`, 'Content-Type': 'text/plain; charset=utf-8'}, payload: `device_status,${tags} state_of_charge=${normalized.state_of_charge},charging=${normalized.charging} ${normalized.timestamp}`};
return [mqttMsg, influxMsg];
